pub(super) fn auto_parse_typed_value(kind: ConfigValueKind, raw: &str) -> Result<ConfigValue, ConfigSetError> {
    match kind {
        ConfigValueKind::Bool => super::parse_bool(raw).map(ConfigValue::Bool),
        ConfigValueKind::U8 => super::parse_u8(raw).map(ConfigValue::U8),
        ConfigValueKind::U16 => super::parse_u16(raw).map(ConfigValue::U16),
        ConfigValueKind::U32 => super::parse_u32(raw).map(ConfigValue::U32),
        ConfigValueKind::U64 => super::parse_u64(raw).map(ConfigValue::U64),
        ConfigValueKind::Usize => super::parse_usize(raw).map(ConfigValue::Usize),
        ConfigValueKind::BoundaryMode => {
            let mut valid = false;
            if raw.eq_ignore_ascii_case("Balanced") { valid = true; }
            if raw.eq_ignore_ascii_case("Compat") { valid = true; }
            if raw.eq_ignore_ascii_case("Strict") { valid = true; }
            if !valid { return Err(ConfigSetError::InvalidValue); }
            Ok(ConfigValue::BoundaryMode(super::BoundaryMode::from_str(raw)))
        }
        ConfigValueKind::DevFsPolicy => {
            let mut valid = false;
            if raw.eq_ignore_ascii_case("Balanced") { valid = true; }
            if raw.eq_ignore_ascii_case("Dev") { valid = true; }
            if raw.eq_ignore_ascii_case("Strict") { valid = true; }
            if !valid { return Err(ConfigSetError::InvalidValue); }
            Ok(ConfigValue::DevFsPolicy(super::DevFsPolicyProfile::from_str(raw)))
        }
        ConfigValueKind::TlsPolicy => {
            let mut valid = false;
            if raw.eq_ignore_ascii_case("Balanced") { valid = true; }
            if raw.eq_ignore_ascii_case("Minimal") { valid = true; }
            if raw.eq_ignore_ascii_case("Strict") { valid = true; }
            if !valid { return Err(ConfigSetError::InvalidValue); }
            Ok(ConfigValue::TlsPolicy(super::TlsPolicyProfile::from_str(raw)))
        }
        ConfigValueKind::VirtualizationExecution => {
            let mut valid = false;
            if raw.eq_ignore_ascii_case("Background") { valid = true; }
            if raw.eq_ignore_ascii_case("Balanced") { valid = true; }
            if raw.eq_ignore_ascii_case("LatencyCritical") { valid = true; }
            if !valid { return Err(ConfigSetError::InvalidValue); }
            Ok(ConfigValue::VirtualizationExecution(super::VirtualizationExecutionClass::from_str(raw)))
        }
        ConfigValueKind::VirtualizationGovernor => {
            let mut valid = false;
            if raw.eq_ignore_ascii_case("Balanced") { valid = true; }
            if raw.eq_ignore_ascii_case("Efficiency") { valid = true; }
            if raw.eq_ignore_ascii_case("Performance") { valid = true; }
            if !valid { return Err(ConfigSetError::InvalidValue); }
            Ok(ConfigValue::VirtualizationGovernor(super::VirtualizationGovernorClass::from_str(raw)))
        }
    }
}
